const fs = require('fs');
const path = require('path');



// 監視対象ファイル (触覚の受容器)
const WATCH_FILES = [
  { path: '/oikos/01_ヘゲモニコン｜Hegemonikon/nous/projects/registry.yaml', label: 'Registry', severity: 'high' },
  { path: '/oikos/01_ヘゲモニコン｜Hegemonikon/kernel/SACRED_TRUTH.md', label: 'Sacred Truth', severity: 'critical' },
  { path: '/oikos/01_ヘゲモニコン｜Hegemonikon/mekhane/ergasterion/n8n/docker-compose.yml', label: 'n8n Docker', severity: 'high' },
  { path: '/oikos/01_ヘゲモニコン｜Hegemonikon/mekhane/symploke/boot_integration.py', label: 'Boot Integration', severity: 'medium' },
  { path: '/oikos/01_ヘゲモニコン｜Hegemonikon/nous/rules/hegemonikon.md', label: 'HGK Rules', severity: 'high' },
  { path: '/oikos/01_ヘゲモニコン｜Hegemonikon/mekhane/fep/attractor.py', label: 'Attractor Engine', severity: 'medium' },
  { path: '/oikos/01_ヘゲモニコン｜Hegemonikon/mekhane/fep/state_spaces_v2.py', label: 'State Spaces', severity: 'medium' }
];

const STATE_FILE = '/oikos/mneme/.hegemonikon/file_monitor_state.json';
const now = new Date();

// 前回の状態を読む
let prevState = {};
try {
  prevState = JSON.parse(fs.readFileSync(STATE_FILE, 'utf-8'));
} catch(e) {
  // 初回実行 — 空で OK
}

var changes = [];
var currentState = {};
var fileStatuses = [];

for (var i = 0; i < WATCH_FILES.length; i++) {
  var wf = WATCH_FILES[i];
  var fp = wf.path;
  try {
    var stat = fs.statSync(fp);
    var mtime = stat.mtimeMs;
    var size = stat.size;
    currentState[fp] = { mtime: mtime, size: size };

    var prev = prevState[fp];
    if (prev) {
      if (prev.mtime !== mtime || prev.size !== size) {
        var sizeDiff = size - (prev.size || 0);
        var sizeStr = sizeDiff > 0 ? '+' + sizeDiff + 'B' : sizeDiff + 'B';
        changes.push({
          label: wf.label,
          path: fp,
          severity: wf.severity,
          sizeDiff: sizeStr,
          oldSize: prev.size,
          newSize: size
        });
        fileStatuses.push('🔴 ' + wf.label + ' (' + sizeStr + ')');
      } else {
        fileStatuses.push('🟢 ' + wf.label);
      }
    } else {
      // 初回 — 変更なし扱い
      fileStatuses.push('⚪ ' + wf.label + ' (初回)');
    }
  } catch(e) {
    fileStatuses.push('⚠️ ' + wf.label + ' (read error)');
    changes.push({
      label: wf.label,
      path: fp,
      severity: 'critical',
      sizeDiff: 'FILE_MISSING',
      oldSize: 0,
      newSize: 0
    });
  }
}

// 状態保存
try {
  var stateDoc = {
    lastScan: now.toISOString(),
    scanCount: ((prevState._meta || {}).scanCount || 0) + 1,
    fileCount: WATCH_FILES.length,
    changesDetected: changes.length
  };
  currentState._meta = stateDoc;
  fs.writeFileSync(STATE_FILE, JSON.stringify(currentState, null, 2), 'utf-8');
} catch(e) {
  // write error — but don't fail
}

var shouldAlert = changes.length > 0;
var scanCount = ((prevState._meta || {}).scanCount || 0) + 1;

// Slack ペイロード
var notifyPayload = '';
if (shouldAlert) {
  var hasCritical = false;
  for (var j = 0; j < changes.length; j++) {
    if (changes[j].severity === 'critical') hasCritical = true;
  }
  var emoji = hasCritical ? '🚨' : '👁️';
  var changeLines = [];
  for (var k = 0; k < changes.length; k++) {
    var c = changes[k];
    var icon = c.severity === 'critical' ? '🔴' : c.severity === 'high' ? '🟠' : '🟡';
    changeLines.push(icon + ' *' + c.label + '* — ' + c.sizeDiff);
  }
  notifyPayload = JSON.stringify({
    blocks: [
      { type: 'header', text: { type: 'plain_text', text: emoji + ' Sympatheia: File Change Detected', emoji: true } },
      { type: 'section', text: { type: 'mrkdwn', text: changeLines.join('\n') } },
      { type: 'context', elements: [{ type: 'mrkdwn', text: '_WF-08 File Monitor | Scan #' + scanCount + '_' }] }
    ]
  });
}

return [{ json: {
  scanCount: scanCount,
  timestamp: now.toISOString(),
  filesMonitored: WATCH_FILES.length,
  changesDetected: changes.length,
  changes: changes,
  fileStatuses: fileStatuses,
  shouldAlert: shouldAlert,
  notifyPayload: notifyPayload
} }];
